patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index f9155cc66031..d94fb1444260 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -2262,6 +2262,70 @@ static Instruction *foldSubOfMinMax(BinaryOperator &I,
     Function *F = Intrinsic::getOrInsertDeclaration(I.getModule(), InvID, Ty);
     return CallInst::Create(F, {Op0, Z});
   }
+  // sub(smin(X+1, Y), smin(X, Y)) --> (X < Y) ? 1 : 0
+  // sub(smax(X, Y), smax(X+1, Y)) --> (X > Y) ? 1 : 0
+  // Also handles umin/umax with nuw instead of nsw.
+  // The add must have the appropriate no-wrap flag, or we can use or disjoint.
+  if (MinMax->hasOneUse()) {
+    Value *A, *B;
+    // Match Op0 as a min/max intrinsic of the same kind
+    if (match(Op0, m_MaxOrMin(m_Value(A), m_Value(B)))) {
+      auto *MM2 = dyn_cast<MinMaxIntrinsic>(Op0);
+      if (!MM2)
+        return nullptr;
+      if (MM2->getIntrinsicID() != MinMax->getIntrinsicID())
+        return nullptr;
+
+      const APInt *C;
+      bool IsValid = false;
+      Value *Other;
+      // Check minmax(X+C, Y) - minmax(X, Y) or minmax(Y, X+C) - minmax(X, Y)
+      if (match(A, m_Add(m_Specific(X), m_APInt(C))) && B == Y) {
+        Other = A;
+        IsValid = true;
+      } else if (match(B, m_Add(m_Specific(X), m_APInt(C))) && A == Y) {
+        Other = B;
+        IsValid = true;
+      }
+
+      // Also check for or disjoint X, 1 which is equivalent to add nuw nsw X, 1
+      if (!IsValid) {
+        if (match(A, m_DisjointOr(m_Specific(X), m_APInt(C))) && B == Y) {
+          Other = A;
+          IsValid = true;
+        } else if (match(B, m_DisjointOr(m_Specific(X), m_APInt(C))) && A == Y) {
+          Other = B;
+          IsValid = true;
+        }
+      }
+
+      if (IsValid) {
+        bool IsSigned = MinMax->isSigned();
+        if (auto *Add = dyn_cast<BinaryOperator>(Other)) {
+          // For add: check no-wrap flag
+          if (Add->getOpcode() == Instruction::Add) {
+            if ((IsSigned && Add->hasNoSignedWrap()) ||
+                (!IsSigned && Add->hasNoUnsignedWrap())) {
+              if (C->isOne()) {
+                Value *Cmp = IsSigned ? Builder.CreateICmpSLT(X, Y)
+                                      : Builder.CreateICmpULT(X, Y);
+                return SelectInst::Create(Cmp, ConstantInt::get(Ty, *C),
+                                          ConstantInt::getNullValue(Ty));
+              }
+            }
+          } else if (Add->getOpcode() == Instruction::Or) {
+            // or disjoint X, 1 is equivalent to add nuw nsw X, 1
+            if (cast<PossiblyDisjointInst>(Add)->isDisjoint() && C->isOne()) {
+              Value *Cmp = IsSigned ? Builder.CreateICmpSLT(X, Y)
+                                    : Builder.CreateICmpULT(X, Y);
+              return SelectInst::Create(Cmp, ConstantInt::get(Ty, *C),
+                                        ConstantInt::getNullValue(Ty));
+            }
+          }
+        }
+      }
+    }
+  }

   return nullptr;
 }

